  peace_ark_stage_9: { ko: "물 위의 방주", de: "Auf dem Wasser", en: "On the water", fr: "Sur l’eau" },
  peace_ark_stage_10: { ko: "무지개 약속", de: "Regenbogenversprechen", en: "Rainbow promise", fr: "Promesse de l’arc-en-ciel" },
  peace_ark_desc_1: { ko: "방주를 지을 재료를 준비해요", de: "Material für die Arche wird vorbereitet", en: "Preparing materials for the ark", fr: "Préparation des matériaux pour l’arche" },
  peace_ark_desc_2: { ko: "방주의 기초가 놓이고 있어요", de: "Die Grundlage der Arche entsteht", en: "The ark’s foundation is being set", fr: "La fondation de l’arche prend forme" },
  peace_ark_desc_3: { ko: "방주의 뼈대가 세워져요", de: "Der Rahmen der Arche wächst", en: "The ark’s frame is rising", fr: "La structure de l’arche s’élève" },
  peace_ark_desc_4: { ko: "말씀동행으로 방주를 지어가요", de: "Mit Gottes Wort wird weitergebaut", en: "Building the ark with each Word walk", fr: "L’arche se construit avec la Parole" },
  peace_ark_desc_5: { ko: "방주의 벽이 단단해지고 있어요", de: "Die Wände der Arche werden fester", en: "The ark’s walls are growing strong", fr: "Les parois de l’arche se renforcent" },
  peace_ark_desc_6: { ko: "지붕과 문이 더해지고 있어요", de: "Dach und Tür werden hinzugefügt", en: "The roof and door are being added", fr: "Le toit et la porte sont ajoutés" },
  peace_ark_desc_7: { ko: "방주의 외형이 완성되어가요", de: "Die Arche nimmt ihre Form an", en: "The ark is taking shape", fr: "L’arche prend sa forme" },
  peace_ark_desc_8: { ko: "동물들이 방주 곁으로 모여요", de: "Die Tiere sammeln sich bei der Arche", en: "Animals gather near the ark", fr: "Les animaux se rassemblent près de l’arche" },
  peace_ark_desc_9: { ko: "방주가 물 위에 떠 있어요", de: "Die Arche treibt auf dem Wasser", en: "The ark is floating on the water", fr: "L’arche flotte sur l’eau" },
  peace_ark_desc_10: { ko: "무지개 아래 감사로 마무리해요", de: "Unter dem Regenbogen endet es mit Dank", en: "Giving thanks under the rainbow", fr: "Rendre grâce sous l’arc-en-ciel" },

  // ── TreeGrowth 하드코딩 ──
  tree_stage_0: { ko: "새 씨앗", de: "Neuer Samen", en: "New seed", fr: "Nouvelle graine" },
  tree_stage_1: { ko: "새싹", de: "Spross", en: "Sprout", fr: "Pousse" },
  tree_stage_2: { ko: "줄기", de: "Stamm", en: "Stem", fr: "Tige" },
  tree_stage_3: { ko: "자라는 나무", de: "Wachsender Baum", en: "Growing tree", fr: "Arbre en croissance" },
  tree_stage_4: { ko: "든든한 나무", de: "Starker Baum", en: "Steady tree", fr: "Arbre solide" },
  tree_stage_5: { ko: "열매 시작", de: "Erste Frucht", en: "Fruit begins", fr: "Début du fruit" },
  tree_stage_6: { ko: "새들의 쉼", de: "Rast der Vögel", en: "Birds rest", fr: "Repos des oiseaux" },
  tree_stage_7: { ko: "새 씨앗", de: "Neuer Samen", en: "New seed", fr: "Nouvelle graine" },
  tree_stage_8: { ko: "새싹 성장", de: "Neuer Spross", en: "New sprout", fr: "Nouvelle pousse" },
  tree_stage_9: { ko: "열매 맺는 나무", de: "Fruchttragender Baum", en: "Fruitful tree", fr: "Arbre fruitier" },
  tree_stage_10: { ko: "풍성한 정원", de: "Üppiger Garten", en: "Flourishing garden", fr: "Jardin abondant" },
  tree_desc_0: { ko: "새 정원이 씨앗으로 시작돼요", de: "Ein neuer Garten beginnt als Samen", en: "A new garden begins as a seed", fr: "Un nouveau jardin commence comme une graine" },
  tree_desc_1: { ko: "말씀의 씨앗이 싹트고 있어요", de: "Der Samen des Wortes sprießt", en: "The seed of the Word is sprouting", fr: "La graine de la Parole germe" },
  tree_desc_2: { ko: "말씀이 마음에 자리를 잡아가요", de: "Das Wort findet seinen Platz im Herzen", en: "The Word is taking root in your heart", fr: "La Parole prend racine dans le cœur" },
  tree_desc_3: { ko: "말씀의 뿌리가 깊어지고 있어요", de: "Die Wurzeln des Wortes werden tiefer", en: "The roots of the Word are growing deeper", fr: "Les racines de la Parole s’approfondissent" },
  tree_desc_4: { ko: "믿음의 줄기가 든든히 서가요", de: "Der Stamm des Glaubens steht fester", en: "The trunk of faith is standing firm", fr: "Le tronc de la foi tient ferme" },
  tree_desc_5: { ko: "말씀이 작은 열매로 나타나요", de: "Das Wort zeigt sich als kleine Frucht", en: "The Word is becoming small fruit", fr: "La Parole devient un petit fruit" },
  tree_desc_6: { ko: "새들이 나무에 깃들었어요", de: "Vögel haben sich im Baum niedergelassen", en: "Birds have come to rest in the tree", fr: "Des oiseaux se sont posés dans l’arbre" },
  tree_desc_7: { ko: "정원 곁에 새 씨앗이 뿌려졌어요", de: "Neben dem Garten wurde ein neuer Samen gesät", en: "A new seed has been planted beside the garden", fr: "Une nouvelle graine a été semée près du jardin" },
  tree_desc_8: { ko: "새 씨앗이 말씀 안에서 자라요", de: "Der neue Samen wächst im Wort", en: "The new seed is growing in the Word", fr: "La nouvelle graine grandit dans la Parole" },
  tree_desc_9: { ko: "또 하나의 나무가 열매를 맺어요", de: "Ein weiterer Baum trägt Frucht", en: "Another tree is bearing fruit", fr: "Un autre arbre porte du fruit" },
  tree_desc_10: { ko: "말씀의 정원이 풍성해졌어요", de: "Der Garten des Wortes ist üppig geworden", en: "The garden of the Word has become abundant", fr: "Le jardin de la Parole est devenu abondant" },

  // {n} placeholder 사용
  tree_day_count:   { ko: "{n}일째", de: "Tag {n}", en: "Day {n}", fr: "Jour {n}" },
  tree_garden_n:    { ko: "{n}번째 정원", de: "{n}. Garten", en: "{n}.garden", fr: "{n}e jardin" },
